#include <iostream>

template <typename T>
T getLarger(T val1, T val2) {
    T result;
    if (val1 > val2) {
        result = val1;
    } else {
        result = val2;
    }
    return result;
}

int main() {
    int num1 = 50; int num2 = 100;
    std::cout << getLarger(num1, num2) << std::endl;

    double dval1 = 15.7; double dval2 = 15.70001;
    std::cout << getLarger(dval1, dval2) << std::endl;

    int a = -5; int b = -10;
    std::cout << getLarger(a, b) << std::endl;

    double x = 0.001; double y = 0.0009;
    std::cout << getLarger(x, y) << std::endl;

    return 0;
}
